# ══════════════════════════════════════════════════════════════════════════════
# DATA LOADING & CLEANING
# ══════════════════════════════════════════════════════════════════════════════

# Columns that identify a covering "unit" (HQ + Division + the MR/SPO on it).
HIER_COLS = ["MR", "Head Qtr", "ASE", "ASM", "RSM", "ZSM", "DSH", "NSH", "BL", "VP"]
TITLECASE_COLS = ["MR", "Head Qtr", "ASE", "ASM", "RSM", "ZSM", "DSH", "NSH", "BL", "VP"]

# Territory-position placeholders used in the MR column instead of a person's name.
NC_PATTERN = re.compile(r"vac{1,2}ant|non[\s\-]?cover", re.IGNORECASE)
VACANCY_NOTE_RE = re.compile(r"Emp\s*:\s*(.+)$", re.IGNORECASE)

MONTH_NUM = {"jan":1, "feb":2, "mar":3, "apr":4, "may":5, "jun":6,
             "jul":7, "aug":8, "sep":9, "oct":10, "nov":11, "dec":12}
MONTH_COL_RE = re.compile(r"^([A-Za-z]{3,})'(\d{2})_(Qty|Amt)$")

STATE_FIXES = {
    "Orissa": "Odisha",
    "Chattisgarh": "Chhattisgarh",
    "Jammu And Kashmir": "Jammu & Kashmir",
}


def _titlecase(x):
    if pd.isna(x):
        return x
    x = str(x).strip()
    return x.title() if x else x


def _normalize_state(x):
    t = _titlecase(x)
    if not t:
        return t
    return STATE_FIXES.get(t, t)


def _classify_coverage(mr_name: str) -> str:
    m = str(mr_name)
    if NC_PATTERN.search(m):
        return "Vacant" if "vac" in m.lower() else "Non-Covering"
    return "Active"


def _vacancy_reason(mr_name: str, coverage_type: str) -> str:
    m = str(mr_name)
    if coverage_type == "Active":
        return ""
    note_m = VACANCY_NOTE_RE.search(m)
    if note_m:
        note = re.sub(r"\(resigned\)\s*$", "", note_m.group(1).strip(), flags=re.I).strip(" .")
        return f"Vacant — last covered by {note} (resigned)" if note else "Vacant position"
    if coverage_type == "Vacant":
        return "Vacant position"
    return "Not in covering territory plan"


def _discover_month_columns(columns):
    """Find every <Mon>'<YY>_Qty / <Mon>'<YY>_Amt pair, regardless of exact
    capitalisation, so new months added to future extracts are picked up
    automatically without touching this script."""
    found = {}
    for c in columns:
        m = MONTH_COL_RE.match(str(c).strip())
        if not m:
            continue
        mon, yr, kind = m.groups()
        key = (mon[:3].lower(), yr)
        if key[0] not in MONTH_NUM:
            continue
        found.setdefault(key, {})[kind] = c
    return found


@st.cache_data(show_spinner="⏳ Loading SPO / MR Coverage Data…", ttl=3600)
def load_data():
    candidates = [
        "All_DIVSPO.xlsx", "All_DIVSPO.xlsb", "All_DIVSPO.xlsm",
        "SPO_Data.xlsx", "data_xlsx.xlsx", "Data.xlsx", "Data.xlsb",
    ]
    path = next((p for p in candidates if os.path.exists(p)), None)
    if path is None:
        return None

    if path.endswith(".xlsb"):
        raw = pd.read_excel(path, engine="pyxlsb")
    else:
        raw = pd.read_excel(path, engine="openpyxl")

    raw.columns = [str(c).strip() for c in raw.columns]
    raw = raw.drop_duplicates()  # exact duplicate product rows (0/0 rows repeated in the master list)

    month_cols = _discover_month_columns(raw.columns)
    if not month_cols:
        return None
    id_cols = [c for c in raw.columns if c not in
               {v for cols in month_cols.values() for v in cols.values()}]

    frames = []
    for (mon, yr), cols in sorted(month_cols.items(),
                                   key=lambda kv: (kv[0][1], MONTH_NUM[kv[0][0]])):
        if "Qty" not in cols or "Amt" not in cols:
            continue
        part = raw[id_cols + [cols["Qty"], cols["Amt"]]].copy()
        part = part.rename(columns={cols["Qty"]: "Sales Qty", cols["Amt"]: "Sales Amt"})
        part["Month"] = pd.Timestamp(year=2000 + int(yr), month=MONTH_NUM[mon], day=1)
        frames.append(part)

    df = pd.concat(frames, ignore_index=True)
    df["Sales Qty"] = pd.to_numeric(df["Sales Qty"], errors="coerce").fillna(0.0)
    df["Sales Amt"] = pd.to_numeric(df["Sales Amt"], errors="coerce").fillna(0.0)

    # ── normalize hierarchy / geography text so "MUMBAI" and "Mumbai" are one HQ ──
    for c in TITLECASE_COLS:
        if c in df.columns:
            df[c] = df[c].apply(_titlecase)
    if "State" in df.columns:
        df["State"] = df["State"].apply(_normalize_state)
    if "Division" in df.columns:
        df["Division"] = df["Division"].astype(str).str.strip()
    if "Products Name" in df.columns:
        df = df.rename(columns={"Products Name": "Product Name"})
    df["Product Name"] = df["Product Name"].astype(str).str.strip()

    df["Month_Label"]  = df["Month"].dt.strftime("%b %Y")
    df["Month_Period"] = df["Month"].dt.to_period("M")

    df["Coverage Type"] = df["MR"].apply(_classify_coverage)
    df["Is Non-Covering"] = df["Coverage Type"] != "Active"
    df["Vacancy Reason"] = [
        _vacancy_reason(mr, ct) for mr, ct in zip(df["MR"], df["Coverage Type"])
    ]

    # HQ+Division level coverage ratio (dedup on the covering unit, not on
    # every product row, so a division with 400 SKUs doesn't outweigh one
    # with 20 when we roll this up to a status label).
    unit = df[["Head Qtr", "Division", "MR", "Is Non-Covering"]].drop_duplicates()
    hq_div_stat = (unit.groupby(["Head Qtr", "Division"])["Is Non-Covering"]
                        .agg(nc="sum", total="count").reset_index())
    hq_div_stat["HQ-Division Status"] = "Covered"
    hq_div_stat.loc[hq_div_stat["nc"] == hq_div_stat["total"], "HQ-Division Status"] = "Non-Covering"
    hq_div_stat.loc[(hq_div_stat["nc"] > 0) & (hq_div_stat["nc"] < hq_div_stat["total"]),
                     "HQ-Division Status"] = "Partial"
    df = df.merge(hq_div_stat[["Head Qtr", "Division", "HQ-Division Status"]],
                   on=["Head Qtr", "Division"], how="left")

    return df


df_full = load_data()
if df_full is None:
    st.error("❌ Data file not found. Place All_DIVSPO.xlsx in the same folder as this app.")
    st.stop()


