# ══════════════════════════════════════════════════════════════════════════════
# APPLY FILTERS
# ══════════════════════════════════════════════════════════════════════════════

df = df_full.copy()
if sel_months:    df = df[df["Month_Period"].isin([month_map[m] for m in sel_months])]
if sel_zones:     df = df[df["ZSM"].isin(sel_zones)]
if sel_regions:   df = df[df["RSM"].isin(sel_regions)]
if sel_mrs:       df = df[df["MR"].isin(sel_mrs)]
if sel_states:    df = df[df["State"].isin(sel_states)]
if sel_hqs:       df = df[df["Head Qtr"].isin(sel_hqs)]
if sel_divisions: df = df[df["Division"].isin(sel_divisions)]
if sel_products:  df = df[df["Product Name"].isin(sel_products)]

# Pure HQ-grain coverage status, computed on whatever slice of divisions /
# hierarchy is currently in scope — this is what "Total HQs / Covered /
# Partial / Non-Covering" KPIs and the drill-down table read from.
if df.empty:
    df["HQ Status"] = []
else:
    _unit = df[["Head Qtr", "Division", "MR", "Is Non-Covering"]].drop_duplicates()
    _g = _unit.groupby("Head Qtr")["Is Non-Covering"].agg(nc="sum", total="count")
    _g["HQ Status"] = "Covered"
    _g.loc[_g["nc"] == _g["total"], "HQ Status"] = "Non-Covering"
    _g.loc[(_g["nc"] > 0) & (_g["nc"] < _g["total"]), "HQ Status"] = "Partial"
    _g["Coverage %"] = (1 - _g["nc"] / _g["total"]) * 100
    df = df.merge(_g[["HQ Status", "Coverage %"]], left_on="Head Qtr", right_index=True, how="left")

if sel_status:
    df = df[df["HQ Status"].isin(sel_status)]


