def fmt_inr(val):
    sign = "-" if val < 0 else ""
    val = abs(val)
    if val >= 1e7:  return f"{sign}₹{val/1e7:.2f} Cr"
    if val >= 1e5:  return f"{sign}₹{val/1e5:.1f} L"
    return f"{sign}₹{val:,.0f}"

def fmt_pct(val, decimals=1):
    return f"{val:.{decimals}f}%"

def sec(icon, title, note=None):
    st.markdown(f"<div class='sec-hdr'><span>{icon}&nbsp; {title}</span></div>",
                unsafe_allow_html=True)
    if note:
        st.markdown(f"<div class='sec-note'>{note}</div>", unsafe_allow_html=True)

def clabel(text):
    st.markdown(f"<div class='chart-label'>{text}</div>", unsafe_allow_html=True)

