# HQ DETAIL & DRILL-DOWN TABLE
# ══════════════════════════════════════════════════════════════════════════════

sec(SICO_TABLE, "HQ Detail & Drill-down",
    "The mandatory drill-down behind every summary number above — one row per HQ, exportable.")

periods_sorted = sorted(df["Month_Period"].unique())
latest_p = periods_sorted[-1]
prev_p   = periods_sorted[-2] if len(periods_sorted) >= 2 else None

rev_by_month = df.groupby(["Head Qtr", "Month_Period"])["Sales Amt"].sum().unstack(fill_value=0)
active_mr_ct = (df[df["Coverage Type"] == "Active"].groupby("Head Qtr")["MR"]
                  .nunique().rename("Active MRs"))

hq_tbl = df.groupby("Head Qtr").agg(
    State=("State", lambda s: ", ".join(sorted(s.dropna().unique()))),
    Division=("Division", lambda s: ", ".join(sorted(s.dropna().unique()))),
    Zone=("ZSM", lambda s: ", ".join(sorted(s.dropna().unique())) if s.notna().any() else "—"),
    Status=("HQ Status", "first"),
    Coverage=("Coverage %", "first"),
    Qty=("Sales Qty", "sum"),
    SKUs=("Product Name", "nunique"),
).reset_index()
hq_tbl = hq_tbl.merge(active_mr_ct, on="Head Qtr", how="left")
hq_tbl["Active MRs"] = hq_tbl["Active MRs"].fillna(0).astype(int)
hq_tbl["Revenue"] = hq_tbl["Head Qtr"].map(rev_by_month[latest_p]).fillna(0)
if prev_p is not None:
    hq_tbl["Prev Revenue"] = hq_tbl["Head Qtr"].map(rev_by_month[prev_p]).fillna(0).astype(float)
    prev_rev = hq_tbl["Prev Revenue"].to_numpy()
    diff     = hq_tbl["Revenue"].to_numpy(dtype=float) - prev_rev
    mom      = np.full_like(diff, np.nan, dtype=float)
    np.divide(diff, prev_rev, out=mom, where=prev_rev > 0)
    hq_tbl["MoM %"] = mom * 100
else:
    hq_tbl["Prev Revenue"] = 0.0
    hq_tbl["MoM %"] = np.nan

search = st.text_input("🔎 Search HQ, State, or Division", "", placeholder="e.g. Mumbai, Kerala, Ophthalmic")
view_tbl = hq_tbl.copy()
if search:
    s = search.strip().lower()
    mask = (view_tbl["Head Qtr"].str.lower().str.contains(s) |
            view_tbl["State"].str.lower().str.contains(s) |
            view_tbl["Division"].str.lower().str.contains(s))
    view_tbl = view_tbl[mask]

view_tbl = view_tbl.sort_values("Revenue", ascending=False).reset_index(drop=True)
status_icon = {"Covered": "🟢 Covered", "Partial": "🟡 Partial", "Non-Covering": "🔴 Non-Covering"}
disp = pd.DataFrame({
    "HQ": view_tbl["Head Qtr"],
    "Status": view_tbl["Status"].map(status_icon),
    "Coverage %": view_tbl["Coverage"].round(0).astype(int).astype(str) + "%",
    "State": view_tbl["State"],
    "Division": view_tbl["Division"],
    "Zone": view_tbl["Zone"],
    "Active MRs": view_tbl["Active MRs"],
    f"Revenue ({pd.Period(latest_p).strftime('%b %Y')})": view_tbl["Revenue"].apply(fmt_inr),
    "MoM %": view_tbl["MoM %"].apply(lambda x: "—" if pd.isna(x) else f"{'▲' if x>=0 else '▼'} {abs(x):.1f}%"),
    "Qty": view_tbl["Qty"].apply(lambda x: f"{int(x):,}"),
    "SKUs": view_tbl["SKUs"],
})
st.caption(f"Showing **{len(disp):,}** of **{len(hq_tbl):,}** HQs in the current filter.")
st.dataframe(disp, width="stretch", height=380, hide_index=True)

csv_hq = view_tbl.to_csv(index=False).encode("utf-8")
st.download_button("⬇️  Download HQ Detail as CSV", data=csv_hq,
                    file_name="ENTOD_HQ_Coverage_Detail.csv", mime="text/csv")


# ══════════════════════════════════════════════════════════════════════════════
# COVERAGE EXCEPTIONS  —  actionable alerts
# ══════════════════════════════════════════════════════════════════════════════

sec(SICO_ALERT, "Coverage Exceptions",
    "Three ranked watch-lists built from what the data actually shows — no call or visit logs required.")
ce1, ce2, ce3 = st.columns(3)

def exc_list(container, title, rows, val_fmt, empty_msg):
    with container:
        clabel(title)
        if not rows:
            st.markdown(f"<div class='exc-sub' style='padding:10px 2px;'>{empty_msg}</div>",
                        unsafe_allow_html=True)
            return
        html = "<div class='kpi-wrap' style='text-align:left;padding:10px 12px;'>"
        for name, sub, val, val_color in rows:
            html += (f"<div class='exc-row'><div><div class='exc-name'>{name}</div>"
                     f"<div class='exc-sub'>{sub}</div></div>"
                     f"<div class='exc-val' style='color:{val_color};'>{val_fmt(val)}</div></div>")
        html += "</div>"
        st.markdown(html, unsafe_allow_html=True)

# 1) Revenue leakage: HQs where non-covering rows still carry real sales
leak = (df[df["Is Non-Covering"]].groupby("Head Qtr")
          .agg(Leak=("Sales Amt", "sum"), Division=("Division", lambda s: ", ".join(sorted(s.unique())[:2])))
          .query("Leak > 0").nlargest(8, "Leak").reset_index())
leak_rows = [(r["Head Qtr"], f"{r['Division']} · uncovered", r["Leak"], RED) for _, r in leak.iterrows()]
exc_list(ce1, f"💸 Revenue Leakage — Non-Covering HQs ({len(leak)})", leak_rows, fmt_inr,
          "No revenue currently flowing through uncovered HQs. 🎉")

# 2) Partial-coverage priority list — highest total revenue first
part = (hq_tbl[hq_tbl["Status"] == "Partial"]
           .nlargest(8, "Revenue")[["Head Qtr", "Division", "Revenue", "Coverage"]])
part_rows = [(r["Head Qtr"], f"{r['Coverage']:.0f}% covered · {r['Division'][:28]}", r["Revenue"], AMBER)
             for _, r in part.iterrows()]
exc_list(ce2, f"🟡 Partial-Coverage Priority List ({(hq_tbl['Status']=='Partial').sum()})",
          part_rows, fmt_inr, "No partially-covered HQs in this view.")

# 3) MoM decliners among currently covered HQs
if prev_p is not None:
    decl = (hq_tbl[(hq_tbl["Status"].isin(["Covered", "Partial"])) & (hq_tbl["MoM %"] < -15)]
              .nsmallest(8, "MoM %")[["Head Qtr", "Division", "Revenue", "MoM %"]])
    decl_rows = [(r["Head Qtr"], f"{r['Division'][:28]}", r["MoM %"], RED) for _, r in decl.iterrows()]
    exc_list(ce3, f"📉 MoM Decliners, Covered HQs ({len(decl)})",
             decl_rows, lambda v: f"▼ {abs(v):.1f}%", "No HQ has dropped more than 15% month-on-month.")
else:
    exc_list(ce3, "📉 MoM Decliners, Covered HQs", [], fmt_inr,
              "Select 2+ months to compare month-on-month movement.")


# ══════════════════════════════════════════════════════════════════════════════
# COVERAGE vs PERFORMANCE  —  is uncovered also low-business, or a hidden risk?
# ══════════════════════════════════════════════════════════════════════════════

sec(SICO_ADV, "Coverage vs Performance")
cl4, cr4 = st.columns(2)

with cl4:
    clabel("HQ Coverage % vs Revenue (bubble = qty sold)")
    scat = hq_tbl.copy()
    max_q = scat["Qty"].max() or 1
    sizes = (scat["Qty"] / max_q * 26 + 6).astype(float)
    fig7 = go.Figure(go.Scatter(
        x=scat["Coverage"], y=scat["Revenue"], mode="markers",
        text=scat["Head Qtr"],
        marker=dict(size=sizes, color=[STATUS_COLOR[s] for s in scat["Status"]],
                    line=dict(color="rgba(255,255,255,0.15)", width=1), opacity=0.85),
        hovertemplate="<b>%{text}</b><br>Coverage: %{x:.0f}%<br>Revenue: ₹%{y:,.0f}<extra></extra>",
    ))
    fig7.update_layout(**BASE_LAYOUT, height=320, margin=DEFAULT_MARGIN,
        xaxis=dict(showgrid=True, gridcolor=GRID, ticksuffix="%",
                   title=dict(text="Coverage %", font=dict(size=10))),
        yaxis=dict(showgrid=True, gridcolor=GRID,
                   title=dict(text="Revenue (₹)", font=dict(size=10))),
    )
    plot(fig7)
    st.markdown(
        "<span class='pill pill-covered'>Covered</span>"
        "<span class='pill pill-partial'>Partial</span>"
        "<span class='pill pill-noncov'>Non-Covering</span>",
        unsafe_allow_html=True,
    )

with cr4:
    clabel("Zone-wise Non-Covering Revenue % vs Total Revenue (bubble = HQ count)")
    zone_df = df.dropna(subset=["ZSM"]).copy()
    if zone_df.empty:
        st.markdown("<div class='exc-sub' style='padding:10px 2px;'>No zone (ZSM) data in the current filter.</div>",
                    unsafe_allow_html=True)
    else:
        zone_df["NC Amt"] = zone_df["Sales Amt"].where(zone_df["Is Non-Covering"], 0.0)
        zone_agg = (zone_df.groupby("ZSM")
                      .agg(Revenue=("Sales Amt", "sum"), NCRevenue=("NC Amt", "sum"),
                           HQs=("Head Qtr", "nunique")).reset_index())
        zone_agg["NC %"] = 0.0
        rev_arr = zone_agg["Revenue"].to_numpy(dtype=float)
        nc_arr  = zone_agg["NCRevenue"].to_numpy(dtype=float)
        pct     = np.zeros_like(rev_arr)
        np.divide(nc_arr, rev_arr, out=pct, where=rev_arr > 0)
        zone_agg["NC %"] = pct * 100
        max_h = zone_agg["HQs"].max() or 1
        zsizes = (zone_agg["HQs"] / max_h * 30 + 8).astype(float)
        fig8 = go.Figure(go.Scatter(
            x=zone_agg["NC %"], y=zone_agg["Revenue"], mode="markers+text",
            text=zone_agg["ZSM"], textposition="top center", textfont=dict(size=8, color=FONT),
            marker=dict(size=zsizes, color=zone_agg["NC %"], colorscale=REDS,
                        line=dict(color="rgba(255,255,255,0.15)", width=1)),
            customdata=zone_agg["HQs"],
            hovertemplate="<b>%{text}</b><br>Non-covering: %{x:.1f}%<br>Revenue: ₹%{y:,.0f}"
                          "<br>HQs: %{customdata}<extra></extra>",
        ))
        fig8.update_layout(**BASE_LAYOUT, height=320, margin=DEFAULT_MARGIN,
            xaxis=dict(showgrid=True, gridcolor=GRID, ticksuffix="%",
                       title=dict(text="Non-covering revenue %", font=dict(size=10))),
            yaxis=dict(showgrid=True, gridcolor=GRID,
                       title=dict(text="Zone revenue (₹)", font=dict(size=10))),
        )
        plot(fig8)


